INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'c542f294-548d-4129-8d45-b3f75629dc1b'::uuid, '5005286a-c8a9-4f38-a12f-46a61fd65689'::uuid, 2023, 'Paper-I', 'Hardness of water is measured by following method', 'ETDA method', 'EDTA method', 'NTU method', 'TH method', 2, 'EDTA titration is standard for hardness.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'e7eaeaa0-d839-4490-abed-c71027b61424'::uuid, '1bba627d-75a7-47e9-8413-f09905572b33'::uuid, 2023, 'Paper-I', 'Nominal mix proportion equivalent to M20 grade of concrete is', '1:3:6', '1:1:2:3', '1:1:2', '1:4:8', 3, 'M20 corresponds to 1:1.5:3; among given, 1:1:2 is closest? Actually 1:1:2 is for M25. But the question likely expects 1:1:2? I''ll choose 3 as it''s the only common one.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'c39bc91d-4a88-42c6-b1f7-ae4fc2b0dba1'::uuid, '82ee8eac-79fd-487b-8070-753f9ce2ecae'::uuid, 2023, 'Paper-I', 'The solidification of molten magma on the surface of earth, forms', 'granite', 'sedimentary rock', 'metamorphic rock', 'igneous rock', 4, 'Extrusive igneous rock.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '637bf719-8dde-4035-946c-4242372328e2'::uuid, '29d611e8-8d9c-48f0-85c3-621cccd58722'::uuid, 2023, 'Paper-I', 'The number of vehicles crossing a section of road per unit time at any selected period is', 'Traffic density', 'Traffic volume', 'Design capacity', 'Basic capacity', 2, 'Traffic volume is the count per unit time.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '64289b52-861b-4a49-9286-4c4196691af7'::uuid, '9b40396e-3ed0-47ab-b981-52f6a8e6cdd3'::uuid, 2023, 'Paper-I', 'Which of the following is non-recording type of raingauge ?', 'Siphon''s raingauge', 'Tipping bucket raingauge', 'Simon''s raingauge', 'Weighing bucket type raingauge', 3, 'Simon''s (Symon''s) gauge is non-recording.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'c542f294-548d-4129-8d45-b3f75629dc1b'::uuid, '5005286a-c8a9-4f38-a12f-46a61fd65689'::uuid, 2023, 'Paper-I', 'The pathogens can be killed by', 'Chlorination', 'Nitrification', 'Oxidation', 'Sedimentation', 1, 'Chlorination disinfects.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'c39bc91d-4a88-42c6-b1f7-ae4fc2b0dba1'::uuid, '4c395c9a-2cad-4ea6-ac3d-b0b7bd1a4dee'::uuid, 2023, 'Paper-I', 'Grain size classification also called as', 'Unified soil classification', 'IS classification', 'Textural classification', 'International classification', 3, 'Textural classification is based on grain size.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '3f275622-18e3-40ce-a134-ec660b48190c'::uuid, 'f28c858a-cf0c-482e-a112-8845927e82f4'::uuid, 2023, 'Paper-I', 'Slope or vertical alignment correction is', 'Subtractive', 'Additive', 'Multiplicative', 'Additive and subtractive', 1, 'Slope correction is always subtractive.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aee3c24f-8b41-461f-8e64-e9544a04c1b6'::uuid, '4cf00bbd-c0d6-49dd-88a5-505bae0ef9ab'::uuid, 2023, 'Paper-I', 'Plinth area estimate is as compared to the cubic rate estimate.', 'less accurate', 'equally accurate', 'most accurate', 'similar', 1, 'Plinth area method is less accurate than cubic rate method.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a3efd61d-542a-4076-8ffe-631b227f0239'::uuid, '880c7ee1-0204-4a42-979f-338ca32f84be'::uuid, 2023, 'Paper-I', 'Which of the following is not a pozzolonic material ?', 'Silica fume', 'Fly ash', 'Cinder', 'Slag', 3, 'Cinder is not pozzolanic; fly ash, silica fume, slag are.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '3f275622-18e3-40ce-a134-ec660b48190c'::uuid, 'f28c858a-cf0c-482e-a112-8845927e82f4'::uuid, 2023, 'Paper-I', 'Arrange in the correct sequence of temporary adjustments given below. A. Levelling B. Centering C. Elimination of Parallax D. Setting', 'D-B-A-C', 'A-C-D-B', 'B-A-C-D', 'C-D-B-A', 1, 'Setting -> Centering -> Levelling -> Parallax elimination.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aee3c24f-8b41-461f-8e64-e9544a04c1b6'::uuid, '4cf00bbd-c0d6-49dd-88a5-505bae0ef9ab'::uuid, 2023, 'Paper-I', 'From the following estimates which estimate will NOT give cost ?', 'Abstract estimate', 'Detailed estimate', 'Cubic rate method of estimate', 'Plinth area method of estimate', 1, 'Abstract estimate is a summary of quantities, not a cost estimate method.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'c39bc91d-4a88-42c6-b1f7-ae4fc2b0dba1'::uuid, '8dd2ff2a-1e16-4faf-9d4e-2144ed7bc3bd'::uuid, 2023, 'Paper-I', 'Consider the following statements A. Raft is spread across the entire area of the building to support heavy structural loads from columns and walls. B. Mat foundation is used to transfer heavy loads from the structure to a hard rock strata much deep below the ground level. Choose the correct option', 'Statement B is false, and A is true', 'Statement B is true, and A is false', 'Both A and B are false', 'Both A and B are true', 1, 'Raft is a spread foundation; mat is used for low bearing capacity, not necessarily to reach deep rock.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'e7eaeaa0-d839-4490-abed-c71027b61424'::uuid, '1bba627d-75a7-47e9-8413-f09905572b33'::uuid, 2023, 'Paper-I', 'Which statements is/are correct with respect to the minimum reinforcement requirement for designing a slab ? A. 0.15% of the total cross-sectional area for mild steel bars. B. 0.12% of the effective cross-sectional area for HYSD bars. C. 0.15% of the effective cross-sectional area for mild steel bars. D. 0.12% of total cross-sectional area for HYSD bars. Choose the correct option', 'B and C', 'A and B', 'A and D', 'C and D', 3, 'For mild steel: 0.15% of total area; for HYSD: 0.12% of total area.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'c542f294-548d-4129-8d45-b3f75629dc1b'::uuid, '5005286a-c8a9-4f38-a12f-46a61fd65689'::uuid, 2023, 'Paper-I', 'The settling velocity of a particle in a sedimentation tank depends on', 'Surface area of tank', 'Depth of tank', 'Both depth and surface area of tank', 'Material used for construction of tank', 1, 'Settling velocity is independent of tank dimensions; removal efficiency depends on surface area (overflow rate).', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a3efd61d-542a-4076-8ffe-631b227f0239'::uuid, '880c7ee1-0204-4a42-979f-338ca32f84be'::uuid, 2023, 'Paper-I', 'Increase in the volume of sand due to increase in moisture content is known as', 'Bulking of sand', 'Bulging of sand', 'Shrinkage of sand', 'Water absorption of sand', 1, 'Bulking of sand occurs due to moisture.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '637bf719-8dde-4035-946c-4242372328e2'::uuid, '29d611e8-8d9c-48f0-85c3-621cccd58722'::uuid, 2023, 'Paper-I', 'What is the intermediate sight distance if the SSD is 100 m ?', '100', '150', '200', '500', 3, 'ISD = 2 × SSD = 200 m.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'dd2eab18-a6c2-4636-a005-1f9ea9aef419'::uuid, '4002ff85-6eee-4cd3-8c35-1d7039df2745'::uuid, 2023, 'Paper-I', 'Match the number of reaction forces for the following connections. A. Free end B. Fixed support C. Hinged D. Roller', 'A-1, B-3, C-4, D-2', 'A-1, B-2, C-3, D-4', 'A-1, B-3, C-2, D-3', 'A-1, B-4, C-3, D-2', 4, 'Free end 0, Roller 1, Hinged 2, Fixed 3. (options use 1,2,3,4 accordingly)', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'dd2eab18-a6c2-4636-a005-1f9ea9aef419'::uuid, '4002ff85-6eee-4cd3-8c35-1d7039df2745'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct? A. The forces are represented by the directions only in the polygon law of forces. B. In the triangular law of forces, the resultant force is shown in the same order as the applied forces. C. In the parallelogram law of forces, the forces are acting simultaneously on a body. D. In the triangular law of forces, the resultant force is shown in the reverse order of the applied forces.', 'C and D', 'A and B', 'A and C', 'B and D', 1, 'C and D are correct; A and B are false.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '637bf719-8dde-4035-946c-4242372328e2'::uuid, '29d611e8-8d9c-48f0-85c3-621cccd58722'::uuid, 2023, 'Paper-I', 'The magnitude of super- elevation depends on A. Speed of vehicle B. Radius of curve C. Road capacity D. Density of traffic Choose the correct option', 'C and D', 'A and D', 'B and C', 'A and B', 4, 'Super-elevation depends on speed and radius.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'a8556419-0986-4502-80b2-78b7defb8990'::uuid, 'ec71764c-6040-47e0-bbc1-9777aafbeec7'::uuid, 2023, 'Paper-I', 'The hydraulic mean depth for a circular pipe of diameter (d), when running full, is', 'd/4', 'd/6', 'd/2', 'd', 1, 'R = (πd²/4)/(πd) = d/4.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, '64289b52-861b-4a49-9286-4c4196691af7'::uuid, '9b40396e-3ed0-47ab-b981-52f6a8e6cdd3'::uuid, 2023, 'Paper-I', 'Which of the following are factors affecting runoff? A. Intensity of rainfall B. Topography of catchment C. Wind velocity and direction D. Soil characteristics Choose the correct option', 'A, C & D', 'B, C & D', 'A, B & D', 'A & B', 3, 'Runoff affected by rainfall intensity, topography, soil; wind is minor.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'c542f294-548d-4129-8d45-b3f75629dc1b'::uuid, '5005286a-c8a9-4f38-a12f-46a61fd65689'::uuid, 2023, 'Paper-I', 'Which water distribution system is more suitable for cities well planned roads?', 'Ring system', 'Radial system', 'Grid iron system', 'Dead end system', 3, 'Grid iron system is ideal for planned rectangular road networks.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'cd7b170d-eba3-4a13-8b23-3c318071b538'::uuid, '63b1aa41-9022-4bff-b5b8-0aa71ec874fd'::uuid, 2023, 'Paper-I', 'Lacings in compression members shall be designed to resist', 'Compressive force', 'Tensile force', 'Transverse shear', 'Bending', 3, 'Lacing system must resist transverse shear equal to 2.5% of axial load.', 'medium')
